const { cities = [], categories = [], batch_size = 20 } = $input.first().json.body;
const apiKey = process.env.GOOGLE_API_KEY || '';

const queries = [];
for (const city of cities) {
  for (const category of categories) {
    queries.push({
      json: {
        query: `${category} in ${city}`,
        city,
        category,
        batch_size,
        apiKey
      }
    });
  }
}

if (queries.length === 0) {
  queries.push({ json: { query: 'restaurants in Kuala Lumpur', city: 'Kuala Lumpur', category: 'restaurants', batch_size: 20, apiKey } });
}

return queries;

const items = [];
for (const item of $input.all()) {
  const places = item.json.places || [];
  for (const place of places) {
    items.push({
      json: {
        place_id: place.id,
        name: place.displayName?.text || '',
        type: place.primaryType || '',
        address: place.formattedAddress || '',
        phone: place.nationalPhoneNumber || '',
        website: place.websiteUri || '',
        rating: place.rating || 0,
        review_count: place.userRatingCount || 0,
        photos_count: (place.photos || []).length,
        photo_refs: (place.photos || []).map(p => p.name),
        maps_url: place.googleMapsUri || '',
        query: item.json.query || '',
        city: item.json.city || '',
        category: item.json.category || ''
      }
    });
  }
}
return items.length > 0 ? items : [{ json: { error: 'No places found' } }];

// Gemini classification: determine industry and lead quality
const leads = $input.all();
const results = [];
const apiKey = process.env.GOOGLE_API_KEY || '';

for (const lead of leads) {
  const { name, type, category, city, address, rating, review_count } = lead.json;

  const prompt = `Classify this Malaysian business for a web design lead generation campaign.
Business: ${name}
Type: ${type}
Category: ${category}
City: ${city}
Address: ${address}
Rating: ${rating} (${review_count} reviews)

Return JSON with: { "industry": "<specific industry>", "sub_industry": "<sub category>", "lead_score": <1-10>, "website_urgency": "<low|medium|high|critical>", "reasoning": "<brief explanation>" }`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${apiKey}`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: prompt }] }],
        generationConfig: { responseMimeType: 'application/json' }
      }
    });

    const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    const classification = JSON.parse(text);

    results.push({
      json: {
        ...lead.json,
        industry: classification.industry || category,
        sub_industry: classification.sub_industry || '',
        lead_score: classification.lead_score || 5,
        website_urgency: classification.website_urgency || 'medium',
        classification_reasoning: classification.reasoning || '',
        status: 'new',
        discovered_at: new Date().toISOString()
      }
    });
  } catch (err) {
    results.push({
      json: {
        ...lead.json,
        industry: category,
        sub_industry: '',
        lead_score: 5,
        website_urgency: 'medium',
        classification_reasoning: 'Gemini API error: ' + err.message,
        status: 'new',
        discovered_at: new Date().toISOString()
      }
    });
  }
}

return results;

const leads = $input.all();
const summary = {
  total_leads: leads.length,
  by_industry: {},
  by_urgency: { low: 0, medium: 0, high: 0, critical: 0 },
  avg_lead_score: 0,
  timestamp: new Date().toISOString()
};

let scoreSum = 0;
for (const lead of leads) {
  const ind = lead.json.industry || 'unknown';
  summary.by_industry[ind] = (summary.by_industry[ind] || 0) + 1;
  const urg = lead.json.website_urgency || 'medium';
  if (summary.by_urgency[urg] !== undefined) summary.by_urgency[urg]++;
  scoreSum += lead.json.lead_score || 0;
}
summary.avg_lead_score = leads.length > 0 ? Math.round((scoreSum / leads.length) * 10) / 10 : 0;

return [{ json: summary }];
